import{initializeApp}from "https://www.gstatic.com/firebasejs/10.13.0/firebase-app.js";import{getFirestore,doc,getDoc,updateDoc,increment}from "https://www.gstatic.com/firebasejs/10.13.0/firebase-firestore.js";const firebaseConfig={apiKey:"AIzaSyA-czG_ZNvVlsYLK3TX64ALr2GzyZjBcY4",authDomain:"tea-addicts.firebaseapp.com",projectId:"tea-addicts",storageBucket:"tea-addicts.firebasestorage.app",messagingSenderId:"363775085178",appId:"1:363775085178:web:6473e20d2fca64890dc9c3",measurementId:"G-MNN2F3VHPJ"};const app=initializeApp(firebaseConfig);const db=getFirestore(app);const counterRef=doc(db,'teaCounter','global');const teaCounter=document.getElementById('tea-counter');const sipButton=document.getElementById('sip-button');const errorMessage=document.getElementById('error-message');const sipSounds=[document.getElementById('sip-sound1'),document.getElementById('sip-sound2'),document.getElementById('sip-sound3')];let localCounter=0;function updateCounter(newCount){teaCounter.textContent=newCount;teaCounter.style.transform="scale(1.2)";setTimeout(()=>teaCounter.style.transform="scale(1)",200)}
function playRandomSipSound(){const randomSound=sipSounds[Math.floor(Math.random()*sipSounds.length)];randomSound.play()}
function showError(message){errorMessage.textContent=message;errorMessage.classList.remove('hidden')}
function fetchCounter(){getDoc(counterRef).then((docSnap)=>{if(docSnap.exists()){localCounter=docSnap.data().count;updateCounter(localCounter)}else{showError("No such document!")}}).catch((error)=>{showError("Error getting document: "+error)})}
sipButton.addEventListener('click',()=>{localCounter++;updateCounter(localCounter);playRandomSipSound();updateDoc(counterRef,{count:increment(1)}).catch((error)=>{showError("Error updating document: "+error);localCounter--;updateCounter(localCounter)})});window.addEventListener('load',fetchCounter)